using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private StatusStrip _statusStrip;

    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 changed the default StatusStrip renderer. Explicitly set
        // System rendering to preserve .NET 8 visual behavior.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }
}

public class SafeDropDownEditor : UITypeEditor
{
    public override object? EditValue(
        System.ComponentModel.ITypeDescriptorContext? context,
        IServiceProvider provider,
        object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService is null)
            return value;

        // .NET 9: DropDownControl(null) now throws ArgumentNullException.
        // Guard against null controls before calling.
        var dropDown = CreateDropDown(value);
        if (dropDown is not null)
        {
            editorService.DropDownControl(dropDown);
            value = GetValueFromDropDown(dropDown);
        }

        return value;
    }

    private Control? CreateDropDown(object? currentValue) => null;
    private object? GetValueFromDropDown(Control control) => null;
}

